type Page = 'overview' | 'lab' | 'report';

type Metric = {
  label: string;
  value: string;
  detail: string;
};

const modelCandidates = [
  { name: 'gpt-5.3-codex', role: 'Primary reasoning + code' },
  { name: 'gpt-5.4-mini', role: 'Fast default worker' },
  { name: 'gpt-5.4-nano', role: 'Cheap fallback / prefilter' },
];

const overviewMetrics: Metric[] = [
  { label: 'Pass Rate', value: '96.8%', detail: 'Thompson routing on eval traffic' },
  { label: 'Latency', value: '420 ms', detail: 'P95 end-to-end response time' },
  { label: 'Cost', value: '$0.018', detail: 'Average cost per successful task' },
  { label: 'Alpha / Beta', value: '0.72 / 0.28', detail: 'Exploit vs explore balance' },
];

const evalSignals = [
  'Routing confidence improved on long-context prompts.',
  'gpt-5.3-codex wins hard tasks; gpt-5.4-mini dominates balanced flows.',
  'gpt-5.4-nano reduces cost on low-risk classification and triage.',
];

export default function App() {
  const [page, setPage] = useState<Page>('overview');
  const [exploreBias, setExploreBias] = useState(28);
  const [taskDifficulty, setTaskDifficulty] = useState<'simple' | 'mixed' | 'hard'>('mixed');

  const simulatedRoute = useMemo(() => {
    const codex = taskDifficulty === 'hard' ? 0.61 : taskDifficulty === 'mixed' ? 0.42 : 0.19;
    const mini = taskDifficulty === 'mixed' ? 0.46 : taskDifficulty === 'simple' ? 0.58 : 0.33;
    const nano = 1 - codex - mini;
    return [
      { ...modelCandidates[0], score: Math.max(0.05, codex) },
      { ...modelCandidates[1], score: Math.max(0.05, mini) },
      { ...modelCandidates[2], score: Math.max(0.05, nano) },
    ];
  }, [taskDifficulty]);

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div className="brand">
          <div className="brand-mark">AS</div>
          <div>
            <div className="brand-title">Agent Sam</div>
            <div className="brand-subtitle">Command Center</div>
          </div>
        </div>

        <nav className="nav">
          <button className={page === 'overview' ? 'nav-item active' : 'nav-item'} onClick={() => setPage('overview')}>Overview</button>
          <button className={page === 'lab' ? 'nav-item active' : 'nav-item'} onClick={() => setPage('lab')}>Routing Lab</button>
          <button className={page === 'report' ? 'nav-item active' : 'nav-item'} onClick={() => setPage('report')}>Eval Report</button>
        </nav>

        <div className="sidebar-panel">
          <div className="sidebar-label">Active router</div>
          <div className="sidebar-value">Thompson Sampling</div>
          <div className="sidebar-copy">Adaptive choice among gpt-5.3-codex, gpt-5.4-mini, and gpt-5.4-nano.</div>
        </div>
      </aside>

      <main className="main">
        <header className="hero">
          <div>
            <span className="eyebrow">Agent Sam / production eval workspace</span>
            <h1>Agent Sam Command Center</h1>
            <p className="hero-copy">
              Monitor Thompson routing, inspect candidate models, and review eval outcomes in a polished three-page console.
            </p>
          </div>
          <div className="hero-card">
            <div className="hero-card-label">Current mode</div>
            <div className="hero-card-value">Adaptive routing</div>
            <div className="hero-chip-row">
              <span className="chip">Safe</span>
              <span className="chip">Fast</span>
              <span className="chip">Cost-aware</span>
            </div>
          </div>
        </header>

        {page === 'overview' && (
          <section className="page">
            <div className="grid metrics-grid">
              {overviewMetrics.map((metric) => (
                <article className="card metric-card" key={metric.label}>
                  <div className="metric-label">{metric.label}</div>
                  <div className="metric-value">{metric.value}</div>
                  <div className="metric-detail">{metric.detail}</div>
                </article>
              ))}
            </div>

            <div className="grid content-grid">
              <article className="card panel">
                <h2>Routing snapshot</h2>
                <p>
                  Thompson routing is balancing exploration and exploitation while holding latency under control.
                </p>
                <div className="progress-list">
                  {simulatedRoute.map((m) => (
                    <div className="progress-row" key={m.name}>
                      <div>
                        <div className="progress-name">{m.name}</div>
                        <div className="progress-role">{m.role}</div>
                      </div>
                      <div className="progress-bar-wrap">
                        <div className="progress-bar" style={{ width: `${Math.round(m.score * 100)}%` }} />
                      </div>
                      <div className="progress-score">{Math.round(m.score * 100)}%</div>
                    </div>
                  ))}
                </div>
              </article>

              <article className="card panel accent-panel">
                <h2>Key signals</h2>
                <ul className="signal-list">
                  {evalSignals.map((s) => (
                    <li key={s}>{s}</li>
                  ))}
                </ul>
              </article>
            </div>
          </section>
        )}

        {page === 'lab' && (
          <section className="page">
            <div className="grid content-grid lab-grid">
              <article className="card panel">
                <h2>Routing Lab</h2>
                <p>Adjust a simplified exploration knob and choose a task profile to simulate the router.</p>

                <label className="control">
                  <div className="control-row">
                    <span>Exploration bias</span>
                    <strong>{exploreBias}%</strong>
                  </div>
                  <input type="range" min="0" max="100" value={exploreBias} onChange={(e) => setExploreBias(Number(e.target.value))} />
                </label>

                <div className="segmented">
                  {(['simple', 'mixed', 'hard'] as const).map((mode) => (
                    <button key={mode} className={taskDifficulty === mode ? 'segment active' : 'segment'} onClick={() => setTaskDifficulty(mode)}>
                      {mode}
                    </button>
                  ))}
                </div>

                <div className="lab-result">
                  <div className="lab-result-title">Recommended route</div>
                  <div className="lab-route">{taskDifficulty === 'hard' ? 'gpt-5.3-codex' : taskDifficulty === 'simple' ? 'gpt-5.4-nano' : 'gpt-5.4-mini'}</div>
                  <div className="lab-copy">Higher exploration can reveal cheaper wins; lower exploration favors stable high-confidence picks.</div>
                </div>
              </article>

              <article className="card panel">
                <h2>Candidate comparison</h2>
                <div className="candidate-list">
                  {modelCandidates.map((m, idx) => (
                    <div className="candidate-item" key={m.name}>
                      <div>
                        <div className="candidate-name">{m.name}</div>
                        <div className="candidate-role">{m.role}</div>
                      </div>
                      <div className="candidate-badge">#{idx + 1}</div>
                    </div>
                  ))}
                </div>
              </article>
            </div>
          </section>
        )}

        {page === 'report' && (
          <section className="page">
            <div className="grid content-grid">
              <article className="card panel report-panel">
                <h2>Eval Report</h2>
                <div className="report-stats">
                  <div>
                    <div className="stat-label">Pass rate</div>
                    <div className="stat-value">96.8%</div>
                  </div>
                  <div>
                    <div className="stat-label">P95 latency</div>
                    <div className="stat-value">420 ms</div>
                  </div>
                  <div>
                    <div className="stat-label">Avg cost</div>
                    <div className="stat-value">$0.018</div>
                  </div>
                </div>
                <div className="report-table">
                  <div className="report-row header"><span>Model</span><span>Win rate</span><span>Notes</span></div>
                  <div className="report-row"><span>gpt-5.3-codex</span><span>54%</span><span>Best on hard reasoning</span></div>
                  <div className="report-row"><span>gpt-5.4-mini</span><span>39%</span><span>Best all-around balance</span></div>
                  <div className="report-row"><span>gpt-5.4-nano</span><span>7%</span><span>Used for cheap triage</span></div>
                </div>
              </article>

              <article className="card panel accent-panel">
                <h2>Decision</h2>
                <p>
                  Keep Thompson routing enabled with a moderate exploration budget. Route difficult tasks to gpt-5.3-codex,
                  use gpt-5.4-mini for most traffic, and reserve gpt-5.4-nano for low-risk shortcuts.
                </p>
                <div className="status-box">
                  <span className="status-dot" />
                  Ready for rollout
                </div>
              </article>
            </div>
          </section>
        )}
      </main>
    </div>
  );
}"},{"path":"src/App.css","content":":root {
  color-scheme: dark;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background:
    radial-gradient(circle at top left, rgba(114, 9, 183, 0.35), transparent 28%),
    radial-gradient(circle at top right, rgba(72, 149, 239, 0.24), transparent 26%),
    linear-gradient(180deg, #07111f 0%, #081426 55%, #050a12 100%);
  color: #e7eefc;
}

* { box-sizing: border-box; }
body { margin: 0; min-width: 320px; min-height: 100vh; }
button, input { font: inherit; }
button { cursor: pointer; }

.app-shell {
  min-height: 100vh;
  display: grid;
  grid-template-columns: 280px 1fr;
}

.sidebar {
  padding: 24px;
  border-right: 1px solid rgba(255,255,255,0.08);
  background: rgba(3, 8, 17, 0.55);
  backdrop-filter: blur(16px);
}

.brand { display: flex; gap: 12px; align-items: center; margin-bottom: 28px; }
.brand-mark {
  width: 48px; height: 48px; border-radius: 16px; display: grid; place-items: center;
  background: linear-gradient(135deg, #7c3aed, #22c55e);
  color: white; font-weight: 800; box-shadow: 0 18px 40px rgba(124, 58, 237, 0.28);
}
.brand-title { font-weight: 800; letter-spacing: 0.2px; }
.brand-subtitle, .sidebar-copy, .metric-detail, .progress-role, .lab-copy, .candidate-role, .hero-copy, .sidebar-label { color: rgba(231, 238, 252, 0.7); }
.nav { display: grid; gap: 10px; }
.nav-item, .segment {
  border: 1px solid rgba(255,255,255,0.08);
  background: rgba(255,255,255,0.04);
  color: #e7eefc;
  padding: 12px 14px;
  border-radius: 14px;
  text-align: left;
}
.nav-item.active, .segment.active { background: linear-gradient(135deg, rgba(124,58,237,0.4), rgba(37,99,235,0.24)); border-color: rgba(165,180,252,0.35); }
.sidebar-panel, .card { border: 1px solid rgba(255,255,255,0.08); background: rgba(8, 15, 28, 0.72); box-shadow: 0 24px 70px rgba(0,0,0,0.25); }
.sidebar-panel { margin-top: 24px; padding: 18px; border-radius: 20px; }
.sidebar-value { font-size: 1.15rem; font-weight: 800; margin: 8px 0; }
.main { padding: 28px; }
.hero {
  display: grid; grid-template-columns: 1.5fr 0.9fr; gap: 20px; align-items: stretch; margin-bottom: 24px;
}
.hero h1 { margin: 10px 0 12px; font-size: clamp(2.2rem, 4vw, 4.4rem); line-height: 0.98; }
.eyebrow { text-transform: uppercase; letter-spacing: 0.16em; font-size: 0.78rem; color: #9cc2ff; }
.hero-card {
  padding: 22px; border-radius: 26px; background: linear-gradient(135deg, rgba(124,58,237,0.28), rgba(14,165,233,0.18));
  border: 1px solid rgba(255,255,255,0.1); display: flex; flex-direction: column; justify-content: center;
}
.hero-card-value { font-size: 1.6rem; font-weight: 800; margin: 6px 0 14px; }
.chip, .status-box, .candidate-badge { display: inline-flex; align-items: center; justify-content: center; border-radius: 999px; }
.hero-chip-row { display: flex; gap: 10px; flex-wrap: wrap; }
.chip { padding: 7px 11px; background: rgba(255,255,255,0.09); border: 1px solid rgba(255,255,255,0.08); }
.page { display: grid; gap: 22px; }
.grid { display: grid; gap: 18px; }
.metrics-grid { grid-template-columns: repeat(4, minmax(0, 1fr)); }
.content-grid { grid-template-columns: 1.3fr 0.9fr; }
.lab-grid { grid-template-columns: 1fr 0.8fr; }
.card { border-radius: 24px; padding: 22px; }
.metric-card { min-height: 150px; }
.metric-label, .stat-label, .sidebar-label { font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.12em; }
.metric-value, .stat-value { font-size: 2rem; font-weight: 850; margin: 10px 0 8px; }
.panel h2 { margin: 0 0 10px; font-size: 1.25rem; }
.progress-list, .candidate-list { display: grid; gap: 14px; margin-top: 18px; }
.progress-row, .candidate-item, .report-row { display: grid; grid-template-columns: 1.2fr 1.6fr auto; gap: 14px; align-items: center; }
.progress-bar-wrap { height: 12px; border-radius: 999px; background: rgba(255,255,255,0.08); overflow: hidden; }
.progress-bar { height: 100%; border-radius: inherit; background: linear-gradient(90deg, #7c3aed, #22c55e); }
.progress-score, .candidate-badge { font-weight: 800; }
.signal-list { margin: 16px 0 0; padding-left: 18px; color: rgba(231,238,252,0.82); display: grid; gap: 10px; }
.accent-panel { background: linear-gradient(180deg, rgba(10,18,35,0.92), rgba(13,23,44,0.82)); }
.control { display: grid; gap: 12px; margin: 18px 0 22px; }
.control-row { display: flex; justify-content: space-between; align-items: center; }
input[type='range'] { width: 100%; accent-color: #8b5cf6; }
.segmented { display: flex; gap: 10px; flex-wrap: wrap; margin-bottom: 18px; }
.segment { padding: 10px 14px; border-radius: 999px; }
.lab-result { padding: 18px; border-radius: 18px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.08); }
.lab-route { font-size: 1.8rem; font-weight: 850; margin: 8px 0; }
.candidate-item { padding: 14px 0; border-bottom: 1px solid rgba(255,255,255,0.08); }
.candidate-item:last-child { border-bottom: 0; }
.candidate-badge { width: 42px; height: 42px; background: rgba(255,255,255,0.08); }
.report-panel { display: grid; gap: 20px; }
.report-stats { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; }
.report-stats > div { padding: 16px; border-radius: 18px; background: rgba(255,255,255,0.05); }
.report-table { display: grid; gap: 10px; }
.report-row { padding: 12px 14px; border-radius: 14px; background: rgba(255,255,255,0.04); }
.report-row.header { background: transparent; color: rgba(231,238,252,0.72); text-transform: uppercase; font-size: 0.82rem; letter-spacing: 0.12em; }
.status-box { margin-top: 18px; padding: 12px 16px; width: fit-content; gap: 10px; background: rgba(34,197,94,0.12); border: 1px solid rgba(34,197,94,0.25); }
.status-dot { width: 10px; height: 10px; border-radius: 50%; background: #22c55e; box-shadow: 0 0 0 6px rgba(34,197,94,0.14); }

@media (max-width: 980px) {
  .app-shell, .hero, .metrics-grid, .content-grid, .lab-grid, .report-stats { grid-template-columns: 1fr; }
  .sidebar { border-right: 0; border-bottom: 1px solid rgba(255,255,255,0.08); }
}

@media (max-width: 640px) {
  .main, .sidebar { padding: 18px; }
  .card, .hero-card, .sidebar-panel { border-radius: 20px; }
  .progress-row, .candidate-item, .report-row { grid-template-columns: 1fr; }
}
